import { BellIcon, PlusIcon, SearchIcon } from "lucide-react";
import { Button } from "@/registry/default/ui/button";
import {
  InputGroup,
  InputGroupAddon,
  InputGroupInput,
} from "@/registry/default/ui/input-group";
import { Separator } from "@/registry/default/ui/separator";
import {
  SidebarInset,
  SidebarProvider,
  SidebarTrigger,
} from "@/registry/default/ui/sidebar";
import { AppSidebar } from "./components/app-sidebar";
import { OrdersTable } from "./components/orders-table";
import { StatCards } from "./components/stat-cards";

export default function Page() {
  return (
    <SidebarProvider>
      <AppSidebar />
      <SidebarInset>
        <header className="flex h-14 shrink-0 items-center gap-2 border-b px-4">
          <SidebarTrigger />
          <Separator className="mx-1 h-4" orientation="vertical" />
          <h1 className="font-semibold text-sm">Dashboard</h1>
          <div className="ms-auto flex items-center gap-2">
            <InputGroup className="hidden w-56 sm:flex">
              <InputGroupInput
                aria-label="Search"
                placeholder="Search…"
                type="search"
              />
              <InputGroupAddon>
                <SearchIcon aria-hidden="true" />
              </InputGroupAddon>
            </InputGroup>
            <Button aria-label="Notifications" size="icon" variant="ghost">
              <BellIcon aria-hidden="true" />
            </Button>
            <Button>
              <PlusIcon aria-hidden="true" />
              New order
            </Button>
          </div>
        </header>
        <div className="flex flex-1 flex-col gap-4 p-4">
          <StatCards />
          <OrdersTable />
        </div>
      </SidebarInset>
    </SidebarProvider>
  );
}

import {
  ArrowDownRightIcon,
  ArrowUpRightIcon,
  CreditCardIcon,
  DollarSignIcon,
  UsersIcon,
} from "lucide-react";
import { Badge } from "@/registry/default/ui/badge";
import {
  Card,
  CardDescription,
  CardHeader,
  CardTitle,
} from "@/registry/default/ui/card";

const stats = [
  {
    change: "+12.5%",
    description: "Total revenue",
    icon: DollarSignIcon,
    trend: "up" as const,
    value: "$45,231.89",
  },
  {
    change: "+8.2%",
    description: "New customers",
    icon: UsersIcon,
    trend: "up" as const,
    value: "2,350",
  },
  {
    change: "-3.1%",
    description: "Active subscriptions",
    icon: CreditCardIcon,
    trend: "down" as const,
    value: "12,234",
  },
  {
    change: "+19.0%",
    description: "Sales this month",
    icon: DollarSignIcon,
    trend: "up" as const,
    value: "573",
  },
];

export function StatCards() {
  return (
    <div className="grid gap-4 sm:grid-cols-2 lg:grid-cols-4">
      {stats.map((stat) => (
        <Card key={stat.description}>
          <CardHeader>
            <CardDescription className="flex items-center gap-2">
              <stat.icon aria-hidden="true" className="size-4" />
              {stat.description}
            </CardDescription>
            <CardTitle className="text-2xl tabular-nums">
              {stat.value}
            </CardTitle>
            <div className="col-start-2 row-span-2 row-start-1 self-start">
              <Badge variant={stat.trend === "up" ? "success" : "error"}>
                {stat.trend === "up" ? (
                  <ArrowUpRightIcon aria-hidden="true" />
                ) : (
                  <ArrowDownRightIcon aria-hidden="true" />
                )}
                {stat.change}
              </Badge>
            </div>
          </CardHeader>
        </Card>
      ))}
    </div>
  );
}

import { Avatar, AvatarFallback } from "@/registry/default/ui/avatar";
import { Badge } from "@/registry/default/ui/badge";
import {
  Card,
  CardDescription,
  CardHeader,
  CardPanel,
  CardTitle,
} from "@/registry/default/ui/card";
import {
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
} from "@/registry/default/ui/table";

type OrderStatus = "Paid" | "Pending" | "Refunded";

const statusVariant: Record<
  OrderStatus,
  "success" | "warning" | "error"
> = {
  Paid: "success",
  Pending: "warning",
  Refunded: "error",
};

const orders: {
  amount: string;
  customer: string;
  date: string;
  email: string;
  id: string;
  initials: string;
  status: OrderStatus;
}[] = [
  {
    amount: "$250.00",
    customer: "Olivia Martin",
    date: "Jun 12, 2026",
    email: "olivia@acme.com",
    id: "#3210",
    initials: "OM",
    status: "Paid",
  },
  {
    amount: "$150.00",
    customer: "Jackson Lee",
    date: "Jun 11, 2026",
    email: "jackson@acme.com",
    id: "#3209",
    initials: "JL",
    status: "Pending",
  },
  {
    amount: "$350.00",
    customer: "Isabella Nguyen",
    date: "Jun 10, 2026",
    email: "isabella@acme.com",
    id: "#3208",
    initials: "IN",
    status: "Paid",
  },
  {
    amount: "$45.00",
    customer: "William Kim",
    date: "Jun 9, 2026",
    email: "will@acme.com",
    id: "#3207",
    initials: "WK",
    status: "Refunded",
  },
  {
    amount: "$540.00",
    customer: "Sofia Davis",
    date: "Jun 8, 2026",
    email: "sofia@acme.com",
    id: "#3206",
    initials: "SD",
    status: "Paid",
  },
];

export function OrdersTable() {
  return (
    <Card>
      <CardHeader>
        <CardTitle>Recent orders</CardTitle>
        <CardDescription>
          Your store made 265 sales this month.
        </CardDescription>
      </CardHeader>
      <CardPanel className="px-0">
        <Table>
          <TableHeader>
            <TableRow>
              <TableHead className="ps-6">Customer</TableHead>
              <TableHead>Order</TableHead>
              <TableHead>Date</TableHead>
              <TableHead>Status</TableHead>
              <TableHead className="pe-6 text-right">Amount</TableHead>
            </TableRow>
          </TableHeader>
          <TableBody>
            {orders.map((order) => (
              <TableRow key={order.id}>
                <TableCell className="ps-6">
                  <div className="flex items-center gap-3">
                    <Avatar>
                      <AvatarFallback>{order.initials}</AvatarFallback>
                    </Avatar>
                    <div className="flex flex-col gap-0.5">
                      <span className="font-medium">{order.customer}</span>
                      <span className="text-muted-foreground text-xs">
                        {order.email}
                      </span>
                    </div>
                  </div>
                </TableCell>
                <TableCell className="text-muted-foreground tabular-nums">
                  {order.id}
                </TableCell>
                <TableCell className="text-muted-foreground">
                  {order.date}
                </TableCell>
                <TableCell>
                  <Badge variant={statusVariant[order.status]}>
                    {order.status}
                  </Badge>
                </TableCell>
                <TableCell className="pe-6 text-right font-medium tabular-nums">
                  {order.amount}
                </TableCell>
              </TableRow>
            ))}
          </TableBody>
        </Table>
      </CardPanel>
    </Card>
  );
}
